mapper.select:
SELECT id, bucket, key, etag, size, content_type, acl, created_at, updated_at
FROM objects
WHERE bucket = #{bucket}
  AND key    = #{key}

SELECT id, bucket, key, etag, size, content_type, acl, created_at, updated_at
FROM objects
WHERE bucket = #{bucket}

    AND key LIKE #{prefix} || '%'


    AND key > #{cursor}

ORDER BY key
LIMIT #{limit}

